  "resources.heroEyebrow": { en: "Updated for 2026", ar: "محدّث لعام 2026" },
  "resources.heroHeading": { en: "Tax Calendar &amp; Resources", ar: "التقويم الضريبي والموارد" },
  "resources.heroLead": { en: "Every major 2026 filing deadline, plain-English tax tips, and direct links to the IRS and Maryland tax agencies &mdash; everything you need to stay ahead of the calendar.", ar: "كل موعد تقديم رئيسي لعام 2026، ونصائح ضريبية مبسطة، وروابط مباشرة لمصلحة الضرائب الأمريكية وجهات الضرائب في ماريلاند &mdash; كل ما تحتاجه لتبقى متقدمًا على المواعيد." },
  "resources.calendarEyebrow": { en: "2026 Tax Calendar", ar: "التقويم الضريبي 2026" },
  "resources.calendarHeading": { en: "Key filing &amp; payment deadlines", ar: "أهم مواعيد التقديم والدفع" },
  "resources.calendarLead": { en: "Individual, business, payroll, and estimated tax deadlines for the 2026 tax year &mdash; the highlighted date is your next one up.", ar: "مواعيد ضريبية للأفراد والشركات والرواتب والضرائب المقدرة لعام 2026 &mdash; التاريخ المميز هو موعدك القادم." },
  "resources.salesTaxTag": { en: "Sales &amp; Use Tax", ar: "ضريبة المبيعات والاستخدام" },
  "resources.salesTaxHeading": { en: "Maryland sales tax deadlines vary by business", ar: "مواعيد ضريبة المبيعات في ماريلاند تختلف حسب النشاط" },
  "resources.salesTaxDesc": { en: "Maryland sales &amp; use tax returns are typically due by the 20th of the month following your assigned filing period (monthly, quarterly, or annually), based on your sales volume. We'll confirm your exact schedule and file on your behalf &mdash; <a href=\"/contact\" data-i18n-inner=\"resources.getInTouchLink\">get in touch</a> to get set up.", ar: "عادةً ما تُستحق إقرارات ضريبة المبيعات والاستخدام في ماريلاند بحلول اليوم العشرين من الشهر التالي لفترة التقديم المحددة لك (شهرية أو فصلية أو سنوية)، حسب حجم مبيعاتك. سنؤكد لك جدولك الدقيق ونقدّم الإقرار نيابة عنك &mdash; <a href=\"/contact\" data-i18n-inner=\"resources.getInTouchLink\">تواصل معنا</a> للبدء." },
  "resources.getInTouchLink": { en: "get in touch", ar: "تواصل معنا" },
  "resources.disclaimer": { en: "Dates above reflect standard IRS filing deadlines for the 2026 tax year. If a date falls on a weekend or federal holiday, the deadline shifts to the next business day. Always confirm exact dates for your situation at <a href=\"https://www.irs.gov\" target=\"_blank\" rel=\"noopener\">IRS.gov</a> or with our team.", ar: "التواريخ أعلاه تعكس المواعيد النهائية القياسية لمصلحة الضرائب الأمريكية لعام 2026. إذا صادف أحد التواريخ عطلة نهاية أسبوع أو عطلة فيدرالية، ينتقل الموعد إلى يوم العمل التالي. تأكد دائمًا من التواريخ الدقيقة لحالتك عبر <a href=\"https://www.irs.gov\" target=\"_blank\" rel=\"noopener\">IRS.gov</a> أو مع فريقنا." },

