  "news.indexEyebrow": { en: "From Our Tax Desk", ar: "من مكتبنا الضريبي" },
  "news.indexHeading": { en: "Tax News & Insights", ar: "أخبار ورؤى ضريبية" },
  "news.indexLead": { en: "Plain-English articles on the tax and bookkeeping topics that matter most to Maryland individuals and small business owners.", ar: "مقالات مبسّطة حول مواضيع الضرائب ومسك الدفاتر الأكثر أهمية للأفراد وأصحاب الشركات الصغيرة في ماريلاند." },
  "news.indexDisclaimer": { en: 'These articles are general information for Maryland individuals and small businesses, not personalized tax, legal, or accounting advice. Always confirm current figures and rules at <a href="https://www.irs.gov" target="_blank" rel="noopener">IRS.gov</a> or <a href="https://www.marylandtaxes.gov" target="_blank" rel="noopener">marylandtaxes.gov</a>, or <a href="/contact">talk with our team</a> about your specific situation.', ar: 'هذه المقالات معلومات عامة للأفراد والشركات الصغيرة في ماريلاند، وليست استشارة ضريبية أو قانونية أو محاسبية شخصية. تأكد دائمًا من الأرقام والقواعد الحالية عبر <a href="https://www.irs.gov" target="_blank" rel="noopener">IRS.gov</a> أو <a href="https://www.marylandtaxes.gov" target="_blank" rel="noopener">marylandtaxes.gov</a>، أو <a href="/contact">تواصل مع فريقنا</a> بخصوص حالتك الخاصة.' },
