  "resources.ctaHeading": { en: "Have a question a webpage can't answer?", ar: "لديك سؤال لا تستطيع الصفحة الإجابة عنه؟" },
  "resources.ctaLead": { en: "Every business is different. Talk to us directly about your specific tax situation.", ar: "كل عمل مختلف. تحدث معنا مباشرة عن وضعك الضريبي الخاص." },

